class Solution {
    public int findMaxK(int[] nums) {
        int maxK = -1;
        boolean[] exists = new boolean[2001];

        for (int num : nums) {
            exists[num + 1000] = true;
        }

        for (int i = 1000; i >= 0; i--) {
            if (exists[i] && exists[1000 - i]) {
                maxK = i;
                break;
            }
        }

        return maxK;
    }
}
